1	import { Hono } from "hono";
2	import { readFile, writeFile, mkdir } from "node:fs/promises";
3	import { join, resolve } from "node:path";
4	
5	const DATA_DIR = process.env.AGENT_EVAL_DATA_DIR ?? resolve(process.cwd(), "data");
6	
7	export const configRoutes = new Hono();
8	
9	function configPath(): string {
10	  return join(DATA_DIR, "eval.config.json");
11	}
12	
13	configRoutes.get("/", async (c) => {
14	  try {
15	    const raw = await readFile(configPath(), "utf-8");
16	    return c.json(JSON.parse(raw));
17	  } catch (err) {
18	    if ((err as NodeJS.ErrnoException).code === "ENOENT") {
19	      return c.json(defaultConfig());
20	    }
21	    return c.json({ error: (err as Error).message }, 500);
22	  }
23	});
24	
25	configRoutes.put("/", async (c) => {
26	  const body = await c.req.json();
27	  await mkdir(DATA_DIR, { recursive: true });
28	  await writeFile(configPath(), JSON.stringify(body, null, 2), "utf-8");
29	  return c.json({ ok: true });
30	});
