68	<script setup lang="ts">
69	import { ref, computed, onMounted, onUnmounted } from "vue";
70	import { api } from "@/api/client";
71	
72	const status = ref<string>("idle");
73	const runId = ref<string | null>(null);
74	const progress = ref({ total: 0, completed: 0, passed: 0, failed: 0 });
75	const cases = ref<any[]>([]);
76	let eventSource: EventSource | null = null;
77	
78	const progressPercent = computed(() =>
79	  progress.value.total > 0 ? (progress.value.completed / progress.value.total) * 100 : 0
80	);
81	
82	const statusText = computed(() => {
83	  switch (status.value) {
84	    case "running": return "运行中...";
85	    case "completed": return "已完成";
86	    case "error": return "出错";
87	    default: return "空闲";
88	  }
89	});
90	
91	const statusColor = computed(() => {
92	  switch (status.value) {
93	    case "running": return "text-blue-600";
94	    case "completed": return "text-green-600";
95	    case "error": return "text-red-600";
96	    default: return "text-gray-600";
97	  }
98	});
99	
100	function statusEmoji(s: string) {
101	  switch (s) {
102	    case "passed": return "✅ 通过";
103	    case "failed": return "❌ 失败";
104	    case "errored": return "💥 错误";
105	    case "timeout": return "⌛ 超时";
106	    case "running": return "🔄 运行中";
107	    default: return "⏳ 等待";
108	  }
109	}
110	
111	onMounted(async () => {
112	  const s = await api.getRunStatus();
113	  status.value = s.status;
114	  runId.value = s.run_id;
115	  if (s.progress) progress.value = s.progress as any;
116	
117	  // Always connect SSE if running or just started
118	  if (s.status === "running" || s.status === "idle") {
119	    connectSSE();
120	  }
121	});
122	
123	function connectSSE() {
124	  eventSource = api.subscribeEvents();
125	  eventSource.onmessage = (e) => {
126	    const data = JSON.parse(e.data);
127	    switch (data.type) {
128	      case "run.started":
129	        status.value = "running";
130	        runId.value = data.run_id;
131	        progress.value.total = data.total;
132	        break;
133	      case "case.completed":
134	        progress.value.completed += 1;
135	        if (data.status === "passed") progress.value.passed += 1;
136	        else progress.value.failed += 1;
137	        cases.value.push(data);
138	        break;
139	      case "run.completed":
140	        status.value = "completed";
141	        eventSource?.close();
142	        break;
143	      case "run.error":
144	        status.value = "error";
145	        eventSource?.close();
146	        break;
147	    }
148	  };
149	}
150	
151	async function abort() {
152	  await api.abortRun();
153	  status.value = "idle";
154	  eventSource?.close();
155	}
156	
157	onUnmounted(() => {
158	  eventSource?.close();
159	});
160	</script>
