3	const validatorBaseSchema = z.object({
4	  weight: z.number().min(0).default(1),
5	  description: z.string().optional(),
6	});
7	
8	const fileExistsValidatorSchema = validatorBaseSchema.extend({
9	  type: z.literal("file_exists"),
10	  path: z.string().min(1),
11	  should_exist: z.boolean().default(true),
12	});
13	
14	const fileDiffValidatorSchema = validatorBaseSchema.extend({
15	  type: z.literal("file_diff"),
16	  path: z.string().min(1),
17	  expected: z.string().optional(),
18	  expected_path: z.string().optional(),
19	  ignore_whitespace: z.boolean().default(false),
20	  ignore_trailing_newline: z.boolean().default(true),
21	});
22	
23	const commandCheckValidatorSchema = validatorBaseSchema.extend({
24	  type: z.literal("command_check"),
25	  command: z.string().min(1),
26	  shell: z.string().default("/bin/sh"),
27	  expected_exit_code: z.number().int().default(0),
28	  expected_stdout: z.string().optional(),
29	  expected_stdout_regex: z.string().optional(),
30	  timeout_ms: z.number().int().positive().default(60_000),
31	  cwd: z.string().optional(),
32	});
33	
34	const regexMatchValidatorSchema = validatorBaseSchema.extend({
35	  type: z.literal("regex_match"),
36	  path: z.string().min(1),
37	  pattern: z.string().min(1),
38	  flags: z.string().default(""),
39	  should_match: z.boolean().default(true),
40	});
41	
42	const jsonMatchValidatorSchema = validatorBaseSchema.extend({
43	  type: z.literal("json_match"),
44	  path: z.string().min(1),
45	  expected: z.unknown(),
46	  expected_path: z.string().optional(),
47	  partial: z.boolean().default(false),
48	});
49	
50	const scriptValidatorSchema = validatorBaseSchema.extend({
51	  type: z.literal("script"),
52	  script: z.string().min(1),
53	  shell: z.string().default("/bin/sh"),
54	  timeout_ms: z.number().int().positive().default(60_000),
55	  expected_exit_code: z.number().int().default(0),
56	});
57	
58	const llmJudgeValidatorSchema = validatorBaseSchema.extend({
59	  type: z.literal("llm_judge"),
60	  criteria: z.array(z.string()).default([]),
61	  rubric: z.string().optional(),
62	  pass_threshold: z.number().min(0).max(10).default(6),
63	});
64	
65	export const validatorSchema = z.discriminatedUnion("type", [
66	  fileExistsValidatorSchema,
67	  fileDiffValidatorSchema,
68	  commandCheckValidatorSchema,
69	  regexMatchValidatorSchema,
70	  jsonMatchValidatorSchema,
71	  scriptValidatorSchema,
72	  llmJudgeValidatorSchema,
73	]);
74	
75	const scoringDimensionSchema = z.object({
76	  name: z.string().min(1),
77	  weight: z.number().min(0).default(1),
78	  description: z.string().optional(),
79	});
80	
81	const scoringConfigSchema = z.object({
82	  dimensions: z.array(scoringDimensionSchema).min(1),
83	  scale: z.number().int().positive().default(10),
84	});
85	
86	const baseCaseSchema = z.object({
87	  id: z.string().min(1),
88	  name: z.string().optional(),
89	  description: z.string().optional(),
90	  prompt: z.string().min(1),
91	  workspace_overlay: z.string().optional(),
92	  timeout_ms: z.number().int().positive().optional(),
93	  tags: z.array(z.string()).default([]),
94	  validators: z.array(validatorSchema).default([]),
95	  reference_answer: z.string().optional(),
96	  setup_commands: z.array(z.string()).default([]),
97	  teardown_commands: z.array(z.string()).default([]),
98	});
99	
100	const passFailCaseSchema = baseCaseSchema.extend({
101	  type: z.literal("pass_fail").default("pass_fail"),
102	});
103	
104	const scoringCaseSchema = baseCaseSchema.extend({
105	  type: z.literal("scoring"),
106	  scoring: scoringConfigSchema,
107	});
108	
109	export const evalCaseSchema = z.preprocess((value) => {
110	  if (value && typeof value === "object" && !Array.isArray(value)) {
111	    const v = value as Record<string, unknown>;
112	    if (v.type === undefined) return { ...v, type: "pass_fail" };
113	  }
114	  return value;
115	}, z.discriminatedUnion("type", [passFailCaseSchema, scoringCaseSchema]));
116	
117	export const datasetSchema = z.object({
118	  version: z.string().default("1"),
119	  name: z.string().optional(),
120	  description: z.string().optional(),
121	  cases: z.array(evalCaseSchema).min(1),
122	});
123	
124	export type Validator = z.infer<typeof validatorSchema>;
125	export type ScoringConfig = z.infer<typeof scoringConfigSchema>;
126	export type ScoringDimension = z.infer<typeof scoringDimensionSchema>;
127	export type EvalCase = z.infer<typeof evalCaseSchema>;
128	export type PassFailCase = z.infer<typeof passFailCaseSchema>;
129	export type ScoringCase = z.infer<typeof scoringCaseSchema>;
130	export type Dataset = z.infer<typeof datasetSchema>;
