117	
118	const router = useRouter();
119	
120	const config = ref<any>({
121	  name: "",
122	  description: "",
123	  opencode: { model: "", provider: {}, mcp: {}, skills: {}, permission: {} },
124	  sandbox: { mode: "local", timeout_ms: 300000 },
125	  execution: { concurrency: 2, case_timeout_ms: 300000, global_timeout_ms: 3600000 },
126	  judge: { type: "openai_compatible", model: "", base_url: "", api_key: "" },
127	  dataset: "./dataset.json",
128	  workspace: "./workspace",
129	  output_dir: "./results",
130	});
131	
132	const hasJudge = ref(false);
133	const providerJson = ref("{}");
134	const datasetJson = ref("{}");
135	const configSaved = ref(false);
136	const datasetSaved = ref(false);
137	const dragOver = ref(false);
138	const message = ref("");
139	const messageType = ref<"success" | "error">("success");
