141	onMounted(async () => {
142	  try {
143	    const cfg = await api.getConfig();
144	    Object.assign(config.value, cfg);
145	    hasJudge.value = !!cfg.judge;
146	    if (!config.value.judge) {
147	      config.value.judge = { type: "openai_compatible", model: "", base_url: "", api_key: "" };
148	    }
149	    providerJson.value = JSON.stringify(config.value.opencode?.provider ?? {}, null, 2);
150	  } catch {}
151	  try {
152	    const ds = await api.getDataset();
153	    datasetJson.value = JSON.stringify(ds, null, 2);
154	  } catch {}
155	});
156	
157	async function saveConfig() {
158	  try {
159	    config.value.opencode.provider = JSON.parse(providerJson.value);
160	    if (!hasJudge.value) delete config.value.judge;
161	    await api.saveConfig(config.value);
162	    configSaved.value = true;
163	    setTimeout(() => (configSaved.value = false), 2000);
164	  } catch (err) {
165	    message.value = `配置保存失败: ${(err as Error).message}`;
166	    messageType.value = "error";
167	  }
168	}
